1	package fan.summer.buildintool.excelsplitter;
2	
3	import java.nio.file.Path;
4	import java.util.List;
5	
6	/**
7	 * Configuration collected across wizard steps, passed between steps.
8	 */
9	public class SplitConfig {
10	
11	    public enum SplitMode {
12	        BY_SHEET("By Sheet"),
13	        BY_COLUMN("By Column Value"),
14	        BY_ROW_COUNT("By Row Count");
15	
16	        public final String label;
17	        SplitMode(String label) { this.label = label; }
18	    }
19	
20	    // Step 1: Source file
21	    public Path   sourceFile;
22	    public List<String> sheetNames;   // All sheet names in source file
23	
24	    // Step 2: Split mode
25	    public SplitMode mode = SplitMode.BY_SHEET;
26	
27	    // BY_COLUMN specific
28	    public String splitColumn;        // Column header name
29	    public int    splitColumnIndex;   // Column index (0-based)
30	
31	    // BY_ROW_COUNT specific
32	    public int rowsPerFile = 1000;
33	
34	    // BY_SHEET specific
35	    public List<String> selectedSheets; // Sheets to split, null means all
36	
37	    // Step 3: Output settings
38	    public Path   outputDir;
39	    public String filePrefix = "";    // Output file name prefix
40	    public boolean keepHeader = true; // Whether to keep header when splitting by column/row
41	
42	    @Override
43	    public String toString() {
44	        return "SplitConfig{mode=" + mode + ", source=" + sourceFile + "}";
45	    }
46	}
