1	package fan.summer.buildintool.excelsplitter;
2	
3	import fan.summer.api.SwissKitJPlugin;
4	import fan.summer.api.component.StepWizard;
5	import javafx.application.Platform;
6	import javafx.concurrent.Task;
7	import javafx.geometry.*;
8	import javafx.scene.Node;
9	import javafx.scene.control.*;
10	import javafx.scene.layout.*;
11	import javafx.stage.DirectoryChooser;
12	import javafx.stage.FileChooser;
13	import org.apache.poi.ss.usermodel.*;
14	import org.apache.poi.ss.usermodel.Cell;
15	
16	import java.io.File;
17	import java.nio.file.*;
18	import java.util.*;
19	import java.util.stream.Collectors;
20	
21	public class ExcelSplitterPlugin implements SwissKitJPlugin {
22	
23	    private Node      view;
24	    private SplitConfig config;
25	
26	    // ── Meta info ────────────────────────────────────────────
27	
28	    @Override public String getId()          { return "com.toolbox.excel-splitter"; }
29	    @Override public String getName()        { return "Excel Splitter"; }
30	    @Override public String getDescription() { return "Split Excel files by Sheet / Column Value / Row Count"; }
31	    @Override public String getCategory()    { return "other"; }
32	    @Override public String getVersion()     { return "1.0.0"; }
33	    @Override public String getIconText()    { return "⊘"; }
34	    @Override public String getIconStyle()   { return "ic-teal"; }
35	    @Override public String getType()        { return "plugin"; }
36	
37	    @Override
38	    public void onActivate() {
39	        // Reset wizard on each entry for easy re-split
40	        view = null;
41	    }
42	
43	    @Override
44	    public Node createView() {
45	        if (view != null) return view;
46	        config = new SplitConfig();
47	        view   = buildWizardView();
48	        return view;
49	    }
50	
51	    // ════════════════════════════════════════════════════
52	    // Wizard build
53	    // ════════════════════════════════════════════════════
54	
55	    private Node buildWizardView() {
56	        StepWizard wizard = new StepWizard();
57	
58	        // ── Step 1: Select file ─────────────────────────────
59	        Step1View step1 = new Step1View(config);
60	        wizard.addStep("Select file", step1,
61	            () -> config.sourceFile != null && Files.exists(config.sourceFile)
62	        );
63	
64	        // ── Step 2: Split mode ─────────────────────────────
65	        Step2View step2 = new Step2View(config);
66	        wizard.addStep("Split mode", step2, () -> {
67	            if (config.mode == SplitConfig.SplitMode.BY_COLUMN
68	                    && (config.splitColumn == null || config.splitColumn.isBlank())) {
69	                return false;
70	            }
71	            if (config.mode == SplitConfig.SplitMode.BY_ROW_COUNT
72	                    && config.rowsPerFile <= 0) {
73	                return false;
74	            }
75	            return true;
76	        });
77	
78	        // ── Step 3: Output settings ─────────────────────────────
79	        Step3View step3 = new Step3View(config);
80	        wizard.addStep("Output settings", step3,
81	            () -> config.outputDir != null && Files.isDirectory(config.outputDir)
82	        );
83	
84	        // ── Step 4: Execute split ─────────────────────────────
85	        Step4View step4 = new Step4View(config);
86	        wizard.addStep("Execute split", step4, () -> true);
87	
88	        // Wire step-change callbacks
89	        wizard.setOnStepChanged((from, to, total) -> {
90	            // On entering step 2: refresh the column selector (file is already selected)
91	            if (to == 1) step2.refresh(config);
92	            // On entering step 4: start the split automatically
93	            if (to == 3) step4.startSplit();
94	        });
95	
96	        // Second listener overwrites the first — kept intentionally for step 4 trigger
97	        wizard.setOnStepChanged((from, to, total) -> {
98	            if (to == 1) step2.refresh(config);
99	            if (to == 3) step4.startSplit();
100	        });
101	
102	        // Wrap in a VBox to add outer padding
103	        VBox root = new VBox(wizard);
104	        VBox.setVgrow(wizard, Priority.ALWAYS);
105	        root.setPadding(new Insets(24));
106	        root.setStyle("-fx-background-color: transparent;");
107	        return root;
108	    }
109	
110	    // ════════════════════════════════════════════════════
111	    // Step 1: Select source file
112	    // ════════════════════════════════════════════════════
113	
114	    static class Step1View extends VBox {
115	        private final SplitConfig config;
116	        private final Label       fileLabel;
117	        private final Label       previewLabel;
118	
119	        Step1View(SplitConfig config) {
120	            this.config = config;
121	            setSpacing(16);
122	            setStyle("-fx-background-color: transparent;");
123	
124	            Label title = sectionTitle("Select Excel file to split");
125	
126	            fileLabel = new Label("No file selected");
127	            fileLabel.setStyle(
128	                "-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 13px;" +
129	                "-fx-font-family: 'SF Mono','Consolas',monospace;"
130	            );
131	            fileLabel.setWrapText(true);
132	
133	            Button pickBtn = glassBtn("📂  Select file", true);
134	            pickBtn.setOnAction(e -> pickFile());
135	
136	            // Drop zone
137	            VBox dropZone = new VBox(12, pickBtn, fileLabel);
138	            dropZone.setAlignment(Pos.CENTER);
139	            dropZone.setPrefHeight(140);
140	            dropZone.setStyle(
141	                "-fx-background-color: rgba(255,255,255,0.03);" +
142	                "-fx-border-color: rgba(255,255,255,0.12);" +
143	                "-fx-border-width: 1; -fx-border-style: dashed;" +
144	                "-fx-border-radius: 12; -fx-background-radius: 12;"
145	            );
146	
147	            // Drag and drop support
148	            dropZone.setOnDragOver(e -> {
149	                if (e.getDragboard().hasFiles()) {
150	                    e.acceptTransferModes(javafx.scene.input.TransferMode.COPY);
151	                    dropZone.setStyle(dropZone.getStyle()
152	                        .replace("rgba(255,255,255,0.03)", "rgba(91,140,247,0.10)")
153	                        .replace("rgba(255,255,255,0.12)", "rgba(91,140,247,0.40)"));
154	                }
155	                e.consume();
156	            });
157	            dropZone.setOnDragExited(e ->
158	                dropZone.setStyle(dropZone.getStyle()
159	                    .replace("rgba(91,140,247,0.10)", "rgba(255,255,255,0.03)")
160	                    .replace("rgba(91,140,247,0.40)", "rgba(255,255,255,0.12)"))
161	            );
162	            dropZone.setOnDragDropped(e -> {
163	                List<File> files = e.getDragboard().getFiles();
164	                if (!files.isEmpty()) loadFile(files.get(0).toPath());
165	                e.setDropCompleted(true);
166	                e.consume();
167	            });
168	
169	            previewLabel = new Label();
170	            previewLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
171	            previewLabel.setWrapText(true);
172	
173	            getChildren().addAll(title, dropZone, previewLabel);
174	        }
175	
176	        private void pickFile() {
177	            FileChooser fc = new FileChooser();
178	            fc.setTitle("Select Excel file");
179	            fc.getExtensionFilters().add(
180	                new FileChooser.ExtensionFilter("Excel files", "*.xlsx", "*.xls", "*.xlsm")
181	            );
182	            File f = fc.showOpenDialog(getScene() != null ? getScene().getWindow() : null);
183	            if (f != null) loadFile(f.toPath());
184	        }
185	
186	        private void loadFile(Path path) {
187	            config.sourceFile = path;
188	            fileLabel.setText(path.getFileName().toString());
189	            fileLabel.setStyle(fileLabel.getStyle()
190	                .replace("rgba(255,255,255,0.40)", "rgba(255,255,255,0.88)"));
191	
192	            // Read sheet names
193	            try (Workbook wb = WorkbookFactory.create(path.toFile(), null, true)) {
194	                List<String> names = new ArrayList<>();
195	                for (int i = 0; i < wb.getNumberOfSheets(); i++)
196	                    names.add(wb.getSheetName(i));
197	                config.sheetNames      = names;
198	                config.selectedSheets  = new ArrayList<>(names);
199	                previewLabel.setText("✓ Contains " + names.size() + "  sheets：" +
200	                    names.stream().limit(5).collect(Collectors.joining(", ")) +
201	                    (names.size() > 5 ? " …" : ""));
202	            } catch (Exception ex) {
203	                previewLabel.setText("❌ Failed to read file：" + ex.getMessage());
204	                config.sourceFile = null;
205	            }
206	        }
207	    }
208	
209	    // ════════════════════════════════════════════════════
210	    // Step 2: Split mode
211	    // ════════════════════════════════════════════════════
212	
213	    static class Step2View extends VBox {
214	        private final SplitConfig config;
215	        private VBox detailPane;
216	
217	        // BY_COLUMN control
218	        private ComboBox<String> columnCombo;
219	        // BY_ROW_COUNT control
220	        private Spinner<Integer> rowSpinner;
221	        // BY_SHEET control
222	        private ListView<String> sheetList;
223	
224	        Step2View(SplitConfig config) {
225	            this.config = config;
226	            setSpacing(16);
227	            setStyle("-fx-background-color: transparent;");
228	            build();
229	        }
230	
231	        private void build() {
232	            Label title = sectionTitle("Select split mode");
233	
234	            // Three radio-button cards
235	            ToggleGroup group = new ToggleGroup();
236	            VBox modeCards = new VBox(8,
237	                modeCard(group, SplitConfig.SplitMode.BY_SHEET,
238	                    "⊞  Split by sheet", "Each sheet outputs one independent file"),
239	                modeCard(group, SplitConfig.SplitMode.BY_COLUMN,
240	                    "🔤  Split by column value",  "Group by different values in a column, one file per group"),
241	                modeCard(group, SplitConfig.SplitMode.BY_ROW_COUNT,
242	                    "📏  Split by row count",  "Output one file every N rows")
243	            );
244	
245	            // Default select first
246	            ((RadioButton) modeCards.getChildren().get(0)
247	                .lookup(".radio-button") != null
248	                ? modeCards.getChildren().get(0)
249	                : modeCards.getChildren().get(0))
250	                .getClass(); // Trigger once to ensure initialization
251	
252	            // Select first Toggle
253	            group.getToggles().get(0).setSelected(true);
254	            config.mode = SplitConfig.SplitMode.BY_SHEET;
255	
256	            detailPane = new VBox();
257	            detailPane.setStyle("-fx-background-color: transparent;");
258	
259	            group.selectedToggleProperty().addListener((obs, o, n) -> {
260	                if (n != null) {
261	                    config.mode = (SplitConfig.SplitMode) n.getUserData();
262	                    refreshDetail();
263	                }
264	            });
265	
266	            refreshDetail();
267	            getChildren().addAll(title, modeCards, detailPane);
268	        }
269	
270	        /** Refresh dynamic content (column list etc.) when the source file changes */
271	        void refresh(SplitConfig config) {
272	            refreshDetail();
273	        }
274	
275	        private void refreshDetail() {
276	            detailPane.getChildren().clear();
277	            detailPane.setPadding(new Insets(4, 0, 0, 0));
278	
279	            switch (config.mode) {
280	                case BY_SHEET -> {
281	                    if (config.sheetNames == null || config.sheetNames.isEmpty()) return;
282	                    sheetList = new ListView<>();
283	                    sheetList.getItems().addAll(config.sheetNames);
284	                    sheetList.getSelectionModel().setSelectionMode(SelectionMode.MULTIPLE);
285	                    sheetList.getSelectionModel().selectAll();
286	                    sheetList.setPrefHeight(Math.min(config.sheetNames.size() * 32 + 8, 160));
287	                    sheetList.setStyle(
288	                        "-fx-background-color: rgba(255,255,255,0.04);" +
289	                        "-fx-border-color: rgba(255,255,255,0.10); -fx-border-radius: 8;" +
290	                        "-fx-background-radius: 8; -fx-text-fill: white;"
291	                    );
292	                    sheetList.getSelectionModel().selectedItemProperty().addListener((o, ov, nv) ->
293	                        config.selectedSheets = new ArrayList<>(
294	                            sheetList.getSelectionModel().getSelectedItems())
295	                    );
296	                    detailPane.getChildren().addAll(
297	                        subLabel("Select sheets to export (multiple allowed)"), sheetList
298	                    );
299	                }
300	                case BY_COLUMN -> {
301	                    columnCombo = new ComboBox<>();
302	                    columnCombo.setPromptText("Column to split by...…");
303	                    columnCombo.setMaxWidth(Double.MAX_VALUE);
304	                    columnCombo.setStyle(comboStyle());
305	
306	                    // Read first row header from file
307	                    if (config.sourceFile != null) {
308	                        try (Workbook wb = WorkbookFactory.create(
309	                                config.sourceFile.toFile(), null, true)) {
310	                            Sheet s = wb.getSheetAt(0);
311	                            Row header = s.getRow(s.getFirstRowNum());
312	                            if (header != null) {
313	                                for (int c = header.getFirstCellNum();
314	                                     c < header.getLastCellNum(); c++) {
315	                                    Cell cell = header.getCell(c);
316	                                    if (cell != null) {
317	                                        String val = cell.toString().trim();
318	                                        if (!val.isEmpty()) {
319	                                            columnCombo.getItems().add(val);
320	                                        }
321	                                    }
322	                                }
